import React, {createContext, useCallback, useContext, useEffect, useMemo, useRef, useState} from "react";
import KitsToast from "../components/Toast";
import KitsConfirm from "../components/ConfirmDialog";
import KitsDialog from "../components/Dialog";
import KitsConfirmPopup from "../components/ConfirmPopup";
import type {
    IConfirmDialogProps,
    IConfirmPopupProps,
    IDialogState,
    IKitsToastRef,
    IToastFunction,
    IToastParams,
    ToastPosition,
} from "@lmb-it/kitsconcerto-types";

interface Ctx {
    confirm: (props: IConfirmDialogProps) => void;
    confirmPopup: (props: IConfirmPopupProps) => void;
    dialog: (props: IDialogState) => void;
    toast: IToastFunction;
    toastDismiss: (position?: ToastPosition) => void;
    toastDismissAll: () => void;
    alert: (message: React.ReactNode, opts?: IConfirmDialogProps) => Promise<void>;
    confirmAsync: (opts: IConfirmDialogProps) => Promise<boolean>;
    prompt: (
        render: (api: { resolve: (v: any) => void; reject: () => void; hide: () => void }) => React.ReactNode,
        opts?: IConfirmDialogProps
    ) => Promise<any>;
}

const PopupContext = createContext<Ctx>(null as any);

const PopupProvider: React.FC<React.PropsWithChildren> = ({children}) => {
    const toastRef = useRef<IKitsToastRef>(null);

    // --- Confirm ---
    const [confirmState, setConfirmState] = useState<IConfirmDialogProps>({visible: false});
    const confirmPromiseRef = useRef<{ resolve?: (v: any) => void; reject?: (r?: any) => void }>({});

    const hideConfirm = useCallback(() => setConfirmState(s => ({...s, visible: false})), []);
    const doAccept = useCallback(() => {
        confirmPromiseRef.current.resolve?.(true);
        confirmPromiseRef.current = {};
        hideConfirm();
    }, [hideConfirm]);
    const doReject = useCallback(() => {
        confirmPromiseRef.current.resolve?.(false);
        confirmPromiseRef.current = {};
        hideConfirm();
    }, [hideConfirm]);

    // --- ConfirmPopup ---
    const [confirmPopupState, setConfirmPopupState] = useState<IConfirmPopupProps>({visible: false});
    const hideConfirmPopup = useCallback((result) => setConfirmPopupState(s => ({...s, visible: false})), []);

    // --- Dialog ---
    const [dialogState, setDialogState] = useState<IDialogState>({visible: false});
    // @ts-ignore
    const onCloseRef = useRef<(() => void) | undefined>();

    useEffect(() => {
        onCloseRef.current = dialogState.onClose;
    }, [dialogState.onClose]);

    const hideDialog = useCallback(() => {
        setDialogState(s => ({...s, visible: false}));
        onCloseRef.current?.();
    }, []);

    // --- Cleanup pending promises on unmount ---
    useEffect(() => {
        return () => {
            confirmPromiseRef.current.reject?.();
            confirmPromiseRef.current = {};
        };
    }, []);

    // --- Toast API ---
    const toast = useCallback<IToastFunction>((...a) => {
        toastRef.current?.toast(...(a as IToastParams));
    }, []);

    const toastDismiss = useCallback((position?: ToastPosition) => {
        toastRef.current?.dismiss?.(position);
    }, []);

    const toastDismissAll = useCallback(() => {
        toastRef.current?.dismissAll?.();
    }, []);

    // --- Confirm API ---
    const confirm = useCallback((props: IConfirmDialogProps) => {
        setConfirmState({visible: true, acceptLabel: "Accept", rejectLabel: "Reject", ...props});
    }, []);

    const confirmPopup = useCallback((props: IConfirmPopupProps) => {
        setConfirmPopupState({visible: true, ...props});
    }, []);

    const dialog = useCallback(({visible = true, ...props}: IDialogState) => {
        setDialogState({visible, ...props});
    }, []);

    const alert = useCallback((message: React.ReactNode, opts: IConfirmDialogProps = {}) =>
        new Promise<void>(resolve => {
            confirmPromiseRef.current = {resolve: () => resolve()};
            setConfirmState({
                visible: true,
                header: opts.header ?? "Alert",
                message,
                defaultUI: true,
                acceptLabel: opts.acceptLabel ?? "OK",
                type: opts.type,
                icon: opts.icon,
                headless: opts.headless,
            });
        }), []);

    const confirmAsync = useCallback((opts: IConfirmDialogProps) =>
        new Promise<boolean>(resolve => {
            confirmPromiseRef.current = {resolve};
            setConfirmState({
                visible: true,
                defaultUI: true,
                acceptLabel: opts.acceptLabel ?? "Yes",
                rejectLabel: opts.rejectLabel ?? "No",
                ...opts,
            });
        }), []);

    const prompt = useCallback((
        render: (api: { resolve: (v: any) => void; reject: () => void; hide: () => void }) => React.ReactNode,
        opts: IConfirmDialogProps = {}
    ) =>
        new Promise<any>((resolve, reject) => {
            confirmPromiseRef.current = {resolve, reject};
            const hide = () => {
                setDialogState(s => ({...s, visible: false}));
                confirmPromiseRef.current = {};
            };
            setDialogState({
                visible: true,
                header: opts.header,
                children: render({
                    resolve: (v) => {
                        resolve(v);
                        hide();
                    },
                    reject: () => {
                        reject();
                        hide();
                    },
                    hide,
                }),
            });
        }), []);

    // --- Stable context value ---
    const value = useMemo<Ctx>(() => ({
        confirm, confirmPopup, dialog, toast, toastDismiss, toastDismissAll, alert, confirmAsync, prompt,
    }), [confirm, confirmPopup, dialog, toast, toastDismiss, toastDismissAll, alert, confirmAsync, prompt]);

    return (
        <PopupContext.Provider value={value}>
            {children}
            <KitsToast ref={toastRef}/>
            <KitsConfirm onHide={hideConfirm} accept={doAccept} reject={doReject} {...confirmState} />
            <KitsDialog state={dialogState} onHide={hideDialog}/>
            {/*@ts-ignore*/}
            <KitsConfirmPopup onHide={hideConfirmPopup} {...confirmPopupState} />
        </PopupContext.Provider>
    );
};

export const usePopup = () => useContext(PopupContext);
export const useDialog = usePopup; // alias

export default PopupProvider;
